#!/usr/bin/env bash
# workflow-5.sh — 持有与运营(出租 + 持有成本管理) SOP walkthrough for 国内房产投资(房产投资人视角 — 城市与地段选择 / 政策与调控解读 / 一手房与二手房 / 房产金融与杠杆 / 估值与尽职调查 / 交易流程与税费 / 持有运营与出租 / 退出与流动性 / 风险识别 / 房产在个人资产配置中的位置 / 投资者的决策框架与心态 — 聚焦中国大陆,2021 年以来深度下行期的真实市场).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="国内房产投资(房产投资人视角 — 城市与地段选择 / 政策与调控解读 / 一手房与二手房 / 房产金融与杠杆 / 估值与尽职调查 / 交易流程与税费 / 持有运营与出租 / 退出与流动性 / 风险识别 / 房产在个人资产配置中的位置 / 投资者的决策框架与心态 — 聚焦中国大陆,2021 年以来深度下行期的真实市场)"
WORKFLOW="持有与运营(出租 + 持有成本管理)"

usage() {
  cat <<EOF
workflow-5.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-5.sh             # interactive
  ./workflow-5.sh --dry-run
  ./workflow-5.sh --json
  ./workflow-5.sh --explain
  ./workflow-5.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "持有与运营(出租 + 持有成本管理)" 工作流。

一句话: 从「拿到房、成为业主」到「建立一套『租金收入 - 持有成本』的持续运营机制」—— 投资房在持有期不是「躺着等涨」,而是要把净租金回报率和持有成本一笔笔管起来,尤其在资本利得不再可靠的 2024-2025。 (evidence: [T02-S003, T01-S015])

入门 SOP 共 4 步, 失败模式自检 5 项。

相关心智模型:
  • 没有「全国房价」—— 城市与板块分化是第一性问题: 不存在「全国房价怎么样」这回事 —— 2021 年后一线核心、三四线、人口流出城市可能同时涨 / 跌 / 阴跌;「买对城市、买对板块」是国内房产投资的第一性问题,选错城市后面所有努力都白费,而且城市内
  • 中国房产是政策驱动 > 市场驱动 —— 读政策、留余量、不赌政策: 中国房产市场是政策驱动多于市场驱动的市场 —— 限购/限贷/限售/认房认贷/LPR/参考价/房产税/保交楼都是可随时启用或急转的政策工具,「读政策原文」是核心能力;但读政策是为了「判方向、留余量」,不

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**决定出租策略**:长租(稳定、省心、回报率低)还是短租(回报率潜在高、空置和管理成本高、受政策影响大)—— 多数投资房选长租。inputs: 房产位置/类型;outputs: 出租模式。"
  "**定价 + 找租客 + 签租约**:参照同板块同户型真实成交租金(不是挂牌租金)定价,通过平台/中介找租客,签规范租约(租期、租金、押金、维修责任、违约条款)。inputs: 周边租金行情;outputs: 已出租 + 租约。"
  "**建持有成本台账**:逐项记录持有成本 —— 月供利息部分、物业费、取暖费、维修、空置月份损失、资金占用机会成本、(试点城市)房产税。inputs: 各项支出;outputs: 年度持有成本。"
  "**算净租金回报率并定期复盘**:净租金回报率 =(年租金 - 年持有成本)/ 总投入;定期(至少年度)复盘「这笔投资还值不值得继续持有」,而不是默认一直拿着。inputs: 台账 + 租金;outputs: 净回报率 + 持有/退出建议。"
)
declare -a FAILURE_MODES=(
  "**「有租金就是赚」的错觉**:触发原因 = 不记完整持有成本台账;怎么避免 = 逐项记账并算上资金占用机会成本,净回报率为负就是亏。Don't: 看到每月有租金到账就觉得这房「在帮我赚钱」,没算物业/空置/首付的机会成本,实际年年净亏。"
  "**按满租算回报**:触发原因 = 忽略换租空窗;怎么避免 = 按真实出租周期(留 1-2 个月空置)算。"
  "**持有变惯性**:触发原因 = 「买都买了」;怎么避免 = 至少年度复盘持有 vs 退出,主动衔接 W7。"
  "**盲目做短租**:触发原因 = 被短租高回报吸引;怎么避免 = 核查本城短租政策 + 真实空置/管理成本,多数投资房长租更稳。"
  "**Decay risk**: medium —— 出租运营和算账框架稳定(low),但租金行情、房产税进展、LPR/重定价是 12 个月内会变的项,整体 medium。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-5-walkthrough"
fi
